// ─── ASSEMBLE ALL PRODUCTS WITH CATEGORY ─────────────────────
const buildProducts = (arr, category) =>
  arr.map(p => ({ ...p, category }));

const allProducts = [
  ...buildProducts(electronics, 'Electronics'),
  ...buildProducts(clothing, 'Clothing'),
  ...buildProducts(footwear, 'Footwear'),
  ...buildProducts(sports, 'Sports'),
  ...buildProducts(kitchen, 'Kitchen'),
  ...buildProducts(accessories, 'Accessories'),
  ...buildProducts(office, 'Office'),
  ...buildProducts(books, 'Books'),
  ...buildProducts(beauty, 'Beauty'),
  ...buildProducts(toys, 'Toys'),
];

// ─── SEED ─────────────────────────────────────────────────────
const seedDB = async () => {
  try {
    await mongoose.connect(process.env.MONGO_URI);
    console.log('✅ MongoDB Connected');

    await Product.deleteMany();
    await User.deleteMany();
    await Order.deleteMany();
    console.log('🗑  Cleared existing data');

    await User.create({
      name: 'Admin User',
      email: 'admin@ecommerce.com',
      password: 'admin123',
      isAdmin: true,
    });
    await User.create({
      name: 'John Doe',
      email: 'john@example.com',
      password: 'user123',
    });

    const inserted = await Product.insertMany(allProducts);
    const byCategory = {};
    inserted.forEach(p => {
      byCategory[p.category] = (byCategory[p.category] || 0) + 1;
    });

    console.log(`\n🎉 Seeded ${inserted.length} products:`);
    Object.entries(byCategory).forEach(([cat, count]) =>
      console.log(`   ${cat}: ${count} products`)
    );
    console.log('\n👤 Admin:  admin@ecommerce.com / admin123');
    console.log('👤 User:   john@example.com / user123\n');
    process.exit(0);
  } catch (err) {
    console.error('❌ Seed error:', err.message);
    process.exit(1);
  }
};

seedDB();
